+    fn derive_genesis_fingerprint(seed: &[u8]) -> [u8; sizes::PHI_BYTES] {
+        let mut hasher = Sha256::new();
+        hasher.update(b"GENESIS:");
+        hasher.update(&[0x16, 0x18, 0x03, 0x39]); // Golden ratio digits
+        hasher.update(seed);
+        let hash = hasher.finalize();
